body:
In this section, you can learn how to create a materialized view that stores
cumulative sales data for each month. This view uses data from the `sample_supplies.sales`
and `sample_supplies.purchaseOrders` collections. Then, create a function to update
the materialized view each month.

Create a `create_update_view.c` file in your `search-materialized-view` project directory,
and copy and paste the following code into the file. This file performs the following
actions:

- Connects to your MongoDB deployment using the connection string

- Immediately updates the `monthlyPhoneTransactions` materialized view by:

  - Filtering transactions with purchase method of `"Phone"`

  - Unwinding the items array to process each item

  - Grouping transactions by month and year

  - Calculating total sales quantity and price for each month

- Sets up a scheduler that runs on the first day of each month at midnight

- Continues running in the background, automatically refreshing the view on schedule

The materialized view stores aggregated data about phone transactions by month,
which can significantly improve query performance for search operations.

```c
   #include <mongoc/mongoc.h>
   #include <stdio.h>
   #include <stdlib.h>
   #include <time.h>
   #include <unistd.h>

   /* Function to update the materialized view */
   void update_monthly_phone_transactions(mongoc_client_t *client, mongoc_collection_t *collection);

   int main(int argc, char *argv[])
   {
       mongoc_client_t *client;
       mongoc_collection_t *sales;
       mongoc_collection_t *purchase_orders;

       /* Initialize the MongoDB C Driver */
       mongoc_init();

       /* Connect to MongoDB */
       client = mongoc_client_new("<connection-string>");
       sales = mongoc_client_get_collection(client, "sample_supplies", "sales");
       purchase_orders = mongoc_client_get_collection(client, "sample_supplies", "purchaseOrders");

       /* Update immediately on startup */
       update_monthly_phone_transactions(client, sales);
       update_monthly_phone_transactions(client, purchase_orders);
       printf("Initial update completed. Materialized view is ready.\n");

       /* Example of a simple scheduler that updates monthly */
       time_t now;
       struct tm *local_time;
       int day_of_month = 1; /* Update on the 1st of each month */

       while (1) {
           time(&now);
           local_time = localtime(&now);

           if (local_time->tm_mday == day_of_month && local_time->tm_hour == 0 && local_time->tm_min == 0) {
               /* It's midnight on the 1st of the month - update the view */
               update_monthly_phone_transactions(client, sales);
               update_monthly_phone_transactions(client, sales);
               printf("Scheduled update completed at %s", ctime(&now));

               /* Sleep for an hour to avoid multiple updates */
               sleep(3600);
           } else {
               /* Check again in a minute */
               sleep(60);
           }
       }

       /* Clean up */
       mongoc_client_destroy(client);
       mongoc_cleanup();

       return 0;
   }

  void update_monthly_phone_transactions(mongoc_client_t *client, mongoc_collection_t *collection)
   {
       bson_t *pipeline;
       mongoc_cursor_t *cursor;
       const bson_t *doc;
       bson_error_t error;

       /* Create the aggregation pipeline */
       pipeline = BCON_NEW (
           "pipeline", "[",
               "{", "$match", "{", "purchaseMethod", BCON_UTF8("Phone"), "}", "}",
               "{", "$unwind", "{", "path", BCON_UTF8("$items"), "}", "}",
               "{", "$group", "{",
                   "_id", "{", "$dateToString", "{", 
                       "format", BCON_UTF8("%Y-%m"), 
                       "date", BCON_UTF8("$saleDate"),
                   "}", "}",
                   "sales_quantity", "{", "$sum", BCON_UTF8("$items.quantity"), "}",
                   "sales_price", "{", "$sum", BCON_UTF8("$items.price"), "}",
               "}", "}",
               "{", "$set", "{", "sales_price", "{", "$toDouble", BCON_UTF8("$sales_price"), "}", "}", "}",
               "{", "$merge", "{", "into", BCON_UTF8("monthlyPhoneTransactions"), "whenMatched", BCON_UTF8("replace"), "}", "}",
           "]"
       );

       /* Run the aggregation */
       cursor = mongoc_collection_aggregate(
           collection, MONGOC_QUERY_NONE, pipeline, NULL, NULL);

       while (mongoc_cursor_next(cursor, &doc)) {
        /* Consume the cursor to execute the pipeline */
       }


       if (mongoc_cursor_error(cursor, &error)) {
           fprintf(stderr, "Aggregation error: %s\n", error.message);
       }

       /* Clean up */
       bson_destroy(pipeline);
       mongoc_cursor_destroy(cursor);
       mongoc_collection_destroy(collection);
   }
```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

Edit the `CMakeLists.txt` file to add a new target for the view updater:

```c
cmake_minimum_required(VERSION 3.11)
project(search-materialized-view LANGUAGES C)
add_executable (view_updater.out create_update_view.c)
find_package(mongoc <version> REQUIRED)
target_link_libraries(view_updater.out mongoc::mongoc)
```

In your terminal, run the following commands to build and run this
application:

**Input:**

```shell
cmake -S. -Bcmake-build
cmake --build cmake-build --target view_updater.out
./cmake-build/view_updater.out
```

**Output:**

```
Initial update completed. Materialized view is ready.
```

